import ProductCard from "../components/ProductCard";

const products = [
  { id: 1, name: "Laptop", price: 800 },
  { id: 2, name: "Phone", price: 500 },
  { id: 3, name: "Headphones", price: 100 }
];

function Home({ addToCart }) {
  return (
    <div>
      <h2>Products</h2>
      {products.map((product) => (
        <ProductCard 
          key={product.id} 
          product={product} 
          addToCart={addToCart}
        />
      ))}
    </div>
  );
}

export default Home;
